// lib/dnd/glossary/cyberpunk-red.ts — Cyberpunk RED terms (R. Talsorian Games).
//
// The core roll is 1d10 + STAT + SKILL against a DV. Not d20. There are no levels, no classes, no
// hit dice, no proficiency bonus, and no armor class — armor has STOPPING POWER, which subtracts
// from damage and wears out, and is a completely different animal from AC. Roles are jobs with a
// signature Role Ability, not classes; advancement is a continuous IP spend, never a level-up.
import type { SystemGlossary } from './types';

